  add(a: T, b: T): T {
    const type = typeof a;
    if (type === 'string') {
      return a + b;
    } else {
      return a + b;
    }
  }

  subtract(a: T, b: T): T {
    const type = typeof a;
    if (type === 'string') {
      return a - b;
    } else {
      return a - b;
    }
  }

  multiply(a: T, b: T): T {
    const type = typeof a;
    if (type === 'string') {
      return a * b;
    } else {
      return a * b;
    }
  }
}

