solutions.javascript:
// Solution
class Calculator<T> {
  add(a: T, b: T): T {
    if (typeof a === 'string' || typeof b === 'string') {
      return a + b;
    } else {
      return a + b;
    }
  }

  subtract(a: T, b: T): T {
    if (typeof a === 'string' || typeof b === 'string') {
      return a - b;
    } else {
      return a - b;
    }
  }

  multiply(a: T, b: T): T {
    if (typeof a === 'string' || typeof b === 'string') {
      return a * b;
    } else {
      return a * b;
    }
  }
}
